import asyncio
import json
import logging
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol

logging.basicConfig(level=logging.INFO)


@dataclass
class Item:
    item_id: str
    item_type: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    websocket: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.global_lock = asyncio.Lock()
        self.item_locks: Dict[str, asyncio.Lock] = {}

    async def register_player(self, websocket: WebSocketServerProtocol, player_id: str) -> None:
        async with self.global_lock:
            if player_id in self.players:
                raise ValueError("Player already connected")
            self.players[player_id] = Player(player_id=player_id, websocket=websocket)
        await self.send_json(websocket, {"type": "registered", "player_id": player_id})

    async def unregister_player(self, player_id: str) -> None:
        async with self.global_lock:
            player = self.players.pop(player_id, None)
        if player:
            logging.info("Player disconnected: %s", player_id)

    async def send_json(self, websocket: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        await websocket.send(json.dumps(data))

    async def broadcast(self, data: Dict[str, Any]) -> None:
        message = json.dumps(data)
        async with self.global_lock:
            websockets_list = [p.websocket for p in self.players.values()]
        if websockets_list:
            await asyncio.gather(*(ws.send(message) for ws in websockets_list), return_exceptions=True)

    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        lock = self.item_locks.get(item_id)
        if lock is None:
            lock = asyncio.Lock()
            self.item_locks[item_id] = lock
        return lock

    async def create_item(self, owner_id: str, item_type: str) -> Item:
        async with self.global_lock:
            if owner_id not in self.players:
                raise ValueError("Owner not connected")
            item_id = str(uuid.uuid4())
            item = Item(item_id=item_id, item_type=item_type, owner_id=owner_id)
            self.items[item_id] = item
            self.players[owner_id].inventory.add(item_id)
            self._get_item_lock(item_id)
            return item

    async def transfer_item(self, from_id: str, to_id: str, item_id: str) -> Dict[str, Any]:
        if from_id == to_id:
            return {"ok": False, "error": "Cannot transfer to self"}

        async with self.global_lock:
            sender = self.players.get(from_id)
            receiver = self.players.get(to_id)
            item = self.items.get(item_id)
            if sender is None or receiver is None:
                return {"ok": False, "error": "Player not found"}
            if item is None:
                return {"ok": False, "error": "Item not found"}
            if item.owner_id != from_id:
                return {"ok": False, "error": "Not item owner"}

            first_lock, second_lock = (sender.lock, receiver.lock) if from_id < to_id else (receiver.lock, sender.lock)

        async with first_lock:
            async with second_lock:
                async with self._get_item_lock(item_id):
                    if item.owner_id != from_id:
                        return {"ok": False, "error": "Item ownership changed"}
                    sender.inventory.discard(item_id)
                    receiver.inventory.add(item_id)
                    item.owner_id = to_id

        await self.broadcast({
            "type": "item_transferred",
            "item_id": item_id,
            "from": from_id,
            "to": to_id,
        })
        return {"ok": True, "item_id": item_id, "new_owner": to_id}

    async def handle_message(self, websocket: WebSocketServerProtocol, player_id: str, message: str) -> None:
        try:
            data = json.loads(message)
        except json.JSONDecodeError:
            await self.send_json(websocket, {"ok": False, "error": "Invalid JSON"})
            return

        msg_type = data.get("type")
        if msg_type == "create_item":
            item_type = data.get("item_type")
            if not item_type:
                await self.send_json(websocket, {"ok": False, "error": "Missing item_type"})
                return
            try:
                item = await self.create_item(player_id, item_type)
                await self.send_json(websocket, {
                    "ok": True,
                    "type": "item_created",
                    "item_id": item.item_id,
                    "item_type": item.item_type,
                    "owner_id": item.owner_id,
                })
            except Exception as e:
                await self.send_json(websocket, {"ok": False, "error": str(e)})

        elif msg_type == "transfer_item":
            to_id = data.get("to_id")
            item_id = data.get("item_id")
            if not to_id or not item_id:
                await self.send_json(websocket, {"ok": False, "error": "Missing to_id or item_id"})
                return
            result = await self.transfer_item(player_id, to_id, item_id)
            await self.send_json(websocket, result)

        elif msg_type == "inventory":
            async with self.global_lock:
                player = self.players.get(player_id)
                if not player:
                    await self.send_json(websocket, {"ok": False, "error": "Player not found"})
                    return
                inventory = []
                for iid in player.inventory:
                    item = self.items.get(iid)
                    if item:
                        inventory.append({"item_id": item.item_id, "item_type": item.item_type, "owner_id": item.owner_id})
            await self.send_json(websocket, {"ok": True, "inventory": inventory})

        else:
            await self.send_json(websocket, {"ok": False, "error": "Unknown message type"})

    async def connection_handler(self, websocket: WebSocketServerProtocol):
        player_id = None
        try:
            register_msg = await websocket.recv()
            try:
                data = json.loads(register_msg)
            except json.JSONDecodeError:
                await self.send_json(websocket, {"ok": False, "error": "Invalid registration JSON"})
                return

            if data.get("type") != "register" or not data.get("player_id"):
                await self.send_json(websocket, {"ok": False, "error": "First message must be register"})
                return

            player_id = data["player_id"]
            await self.register_player(websocket, player_id)
            logging.info("Player connected: %s", player_id)

            async for message in websocket:
                await self.handle_message(websocket, player_id, message)

        except websockets.ConnectionClosed:
            pass
        except Exception as e:
            logging.exception("Connection error: %s", e)
            try:
                await self.send_json(websocket, {"ok": False, "error": "Server error"})
            except Exception:
                pass
        finally:
            if player_id:
                await self.unregister_player(player_id)

    async def run(self, host: str = "0.0.0.0", port: int = 8765) -> None:
        async with websockets.serve(self.connection_handler, host, port):
            logging.info("Server running on %s:%d", host, port)
            await asyncio.Future()


async def main():
    server = GameServer()
    await server.run()


if __name__ == "__main__":
    asyncio.run(main())